import { CommonModule } from '@angular/common';
import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
}

interface CartItem extends Product {
  quantity: number;
}

const PRODUCTS: Product[] = [
  { id: 'p1', name: 'Wireless Headphones', price: 129.99, stock: 2 },
  { id: 'p2', name: 'Mechanical Keyboard', price: 89.5, stock: 3 },
  { id: 'p3', name: 'Ergonomic Mouse', price: 49.99, stock: 5 },
  { id: 'p4', name: 'USB-C Hub', price: 39.0, stock: 1 }
];

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  products = PRODUCTS;
  cartItems: CartItem[] = [];
  promoCode = '';
  promoApplied = false;
  promoMessage = '';
  cartStatus = '';
  checkoutMessage = '';

  get totalQty(): number {
    return this.cartItems.reduce((sum, item) => sum + item.quantity, 0);
  }

  get subtotal(): number {
    return this.cartItems.reduce(
      (sum, item) => sum + item.price * item.quantity,
      0
    );
  }

  get totalPrice(): number {
    return this.grandTotal;
  }

  get discountAmount(): number {
    return this.promoApplied ? this.subtotal * 0.1 : 0;
  }

  get grandTotal(): number {
    return this.subtotal - this.discountAmount;
  }

  quantityFor(productId: string): number {
    return this.cartItems.find((item) => item.id === productId)?.quantity ?? 0;
  }

  isAtStockLimit(product: Product): boolean {
    return this.quantityFor(product.id) >= product.stock;
  }

  isItemAtStockLimit(item: CartItem): boolean {
    return item.quantity >= item.stock;
  }

  addToCart(product: Product): void {
    const existing = this.cartItems.find((item) => item.id === product.id);
    const currentQuantity = existing?.quantity ?? 0;

    if (currentQuantity >= product.stock) {
      this.announceStockLimit(product);
      return;
    }

    const nextQuantity = currentQuantity + 1;
    if (existing) {
      this.cartItems = this.cartItems.map((item) =>
        item.id === product.id ? { ...item, quantity: nextQuantity } : item
      );
    } else {
      this.cartItems = [...this.cartItems, { ...product, quantity: 1 }];
    }

    this.checkoutMessage = '';
    this.cartStatus =
      nextQuantity === product.stock
        ? product.name + ' reached its stock limit.'
        : product.name + ' added to cart.';
  }

  increaseQty(item: CartItem): void {
    if (item.quantity >= item.stock) {
      this.announceStockLimit(item);
      return;
    }

    const nextQuantity = item.quantity + 1;
    this.cartItems = this.cartItems.map((cartItem) =>
      cartItem.id === item.id
        ? { ...cartItem, quantity: nextQuantity }
        : cartItem
    );
    this.checkoutMessage = '';
    this.cartStatus =
      nextQuantity === item.stock
        ? item.name + ' reached its stock limit.'
        : item.name + ' quantity increased.';
  }

  decreaseQty(item: CartItem): void {
    if (item.quantity <= 1) {
      this.removeItem(item);
      return;
    }

    this.cartItems = this.cartItems.map((cartItem) =>
      cartItem.id === item.id
        ? { ...cartItem, quantity: cartItem.quantity - 1 }
        : cartItem
    );
    this.checkoutMessage = '';
    this.cartStatus = item.name + ' quantity decreased.';
  }

  removeItem(item: CartItem): void {
    this.cartItems = this.cartItems.filter(
      (cartItem) => cartItem.id !== item.id
    );
    this.checkoutMessage = '';
    this.cartStatus = item.name + ' removed from cart.';
  }

  onPromoCodeChange(): void {
    this.promoMessage = '';
  }

  applyPromo(): void {
    const normalizedCode = this.promoCode.trim().toUpperCase();
    this.promoCode = normalizedCode;

    if (normalizedCode === 'SAVE10') {
      this.promoApplied = true;
      this.promoMessage = '10% discount applied.';
      return;
    }

    this.promoApplied = false;
    this.promoMessage = 'Promo code is invalid.';
  }

  checkout(): void {
    if (this.cartItems.length === 0) return;

    this.cartItems = [];
    this.promoCode = '';
    this.promoApplied = false;
    this.promoMessage = '';
    this.cartStatus = '';
    this.checkoutMessage = 'Order placed.';
  }

  private announceStockLimit(product: Product): void {
    this.checkoutMessage = '';
    this.cartStatus = product.name + ' reached its stock limit.';
  }
}
